using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _sut;

    public OrderServiceTests()
    {
        _sut = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    // --- CreateOrder: validation ---

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _sut.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _sut.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _sut.CreateOrder("cust-1", []));
        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    // --- CreateOrder: happy path ---

    [TestMethod]
    public void CreateOrder_SingleItem_ReturnsOrderWithCorrectTotal()
    {
        var items = CreateItems(("Widget", 25.50m, 2));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(51.00m, order.Total);
    }

    [TestMethod]
    public void CreateOrder_MultipleItems_ReturnsSumOfLineItems()
    {
        var items = CreateItems(("Widget", 10m, 3), ("Gadget", 5m, 2));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.AreEqual(40m, order.Total); // (10*3) + (5*2)
    }

    [TestMethod]
    public void CreateOrder_ValidInput_SetsCustomerId()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var order = _sut.CreateOrder("cust-42", items);

        Assert.AreEqual("cust-42", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_GeneratesNonEmptyId()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_CalledTwice_GeneratesUniqueIds()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var order1 = _sut.CreateOrder("cust-1", items);
        var order2 = _sut.CreateOrder("cust-1", items);

        Assert.AreNotEqual(order1.Id, order2.Id);
    }

    [TestMethod]
    public void CreateOrder_ValidInput_SetsCreatedAtToRecentUtcTime()
    {
        var before = DateTime.UtcNow;

        var order = _sut.CreateOrder("cust-1", CreateItems(("Widget", 10m, 1)));

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt:O} should be between {before:O} and {after:O}");
    }

    [TestMethod]
    public void CreateOrder_ValidInput_StoresItemsOnOrder()
    {
        var items = CreateItems(("Widget", 10m, 1), ("Gadget", 5m, 3));

        var order = _sut.CreateOrder("cust-1", items);

        Assert.HasCount(2, order.Items);
    }

    // --- GetOrder ---

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsOrder()
    {
        var created = _sut.CreateOrder("cust-1", CreateItems(("Widget", 10m, 1)));

        var found = _sut.GetOrder(created.Id);

        Assert.IsNotNull(found);
        Assert.AreEqual(created.Id, found.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistentId_ReturnsNull()
    {
        var result = _sut.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    // --- GetOrdersByCustomer ---

    [TestMethod]
    public void GetOrdersByCustomer_ExistingCustomer_ReturnsMatchingOrders()
    {
        _sut.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));
        _sut.CreateOrder("cust-1", CreateItems(("B", 2m, 1)));
        _sut.CreateOrder("cust-2", CreateItems(("C", 3m, 1)));

        var orders = _sut.GetOrdersByCustomer("cust-1");

        Assert.HasCount(2, orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_UnknownCustomer_ReturnsEmptyList()
    {
        _sut.CreateOrder("cust-1", CreateItems(("A", 1m, 1)));

        var orders = _sut.GetOrdersByCustomer("unknown");

        Assert.IsEmpty(orders);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MultipleCustomers_ReturnsOnlyRequestedCustomerOrders()
    {
        _sut.CreateOrder("cust-1", CreateItems(("A", 10m, 1)));
        _sut.CreateOrder("cust-2", CreateItems(("B", 20m, 1)));
        _sut.CreateOrder("cust-3", CreateItems(("C", 30m, 1)));

        var orders = _sut.GetOrdersByCustomer("cust-2");

        var single = Assert.ContainsSingle(orders);
        Assert.AreEqual("cust-2", single.CustomerId);
    }
}

